"use client";

import { useRef, useState, useEffect, useCallback } from "react";
import {
  Play,
  Pause,
  Volume2,
  VolumeX,
  Maximize,
  Minimize,
  X,
  Settings,
} from "lucide-react";

import { Button } from "@/components/ui/button";
import { formatDuration } from "@/lib/video/metadata";

/* ============================================
   VideoPlayer — Reusable video player
   Play, Pause, Fullscreen, Seek, Volume,
   Playback Speed, Poster
   ============================================ */

type VideoPlayerProps = {
  src: string;
  title?: string;
  poster?: string;
  onClose?: () => void;
  autoPlay?: boolean;
};

const PLAYBACK_SPEEDS = [0.5, 0.75, 1, 1.25, 1.5, 2];

export function VideoPlayer({
  src,
  title,
  poster,
  onClose,
  autoPlay = false,
}: VideoPlayerProps) {
  const videoRef = useRef<HTMLVideoElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const [isPlaying, setIsPlaying] = useState(false);
  const [currentTime, setCurrentTime] = useState(0);
  const [duration, setDuration] = useState(0);
  const [volume, setVolume] = useState(1);
  const [isMuted, setIsMuted] = useState(false);
  const [isFullscreen, setIsFullscreen] = useState(false);
  const [showSpeedMenu, setShowSpeedMenu] = useState(false);
  const [playbackRate, setPlaybackRate] = useState(1);

  useEffect(() => {
    const video = videoRef.current;
    if (!video) return;

    const onTimeUpdate = () => setCurrentTime(video.currentTime);
    const onDurationChange = () => setDuration(video.duration);
    const onPlay = () => setIsPlaying(true);
    const onPause = () => setIsPlaying(false);

    video.addEventListener("timeupdate", onTimeUpdate);
    video.addEventListener("durationchange", onDurationChange);
    video.addEventListener("play", onPlay);
    video.addEventListener("pause", onPause);

    return () => {
      video.removeEventListener("timeupdate", onTimeUpdate);
      video.removeEventListener("durationchange", onDurationChange);
      video.removeEventListener("play", onPlay);
      video.removeEventListener("pause", onPause);
    };
  }, []);

  useEffect(() => {
    const onFullscreenChange = () => {
      setIsFullscreen(document.fullscreenElement === containerRef.current);
    };
    document.addEventListener("fullscreenchange", onFullscreenChange);
    return () => document.removeEventListener("fullscreenchange", onFullscreenChange);
  }, []);

  const togglePlay = useCallback(() => {
    const video = videoRef.current;
    if (!video) return;
    if (isPlaying) video.pause();
    else video.play();
  }, [isPlaying]);

  const handleSeek = useCallback((e: React.ChangeEvent<HTMLInputElement>) => {
    const video = videoRef.current;
    if (!video) return;
    const time = Number(e.target.value);
    video.currentTime = time;
    setCurrentTime(time);
  }, []);

  const handleVolume = useCallback((e: React.ChangeEvent<HTMLInputElement>) => {
    const video = videoRef.current;
    if (!video) return;
    const vol = Number(e.target.value);
    video.volume = vol;
    video.muted = vol === 0;
    setVolume(vol);
    setIsMuted(vol === 0);
  }, []);

  const toggleMute = useCallback(() => {
    const video = videoRef.current;
    if (!video) return;
    video.muted = !video.muted;
    setIsMuted(video.muted);
  }, []);

  const toggleFullscreen = useCallback(() => {
    const container = containerRef.current;
    if (!container) return;
    if (document.fullscreenElement) {
      document.exitFullscreen();
    } else {
      container.requestFullscreen();
    }
  }, []);

  const changePlaybackRate = useCallback((rate: number) => {
    const video = videoRef.current;
    if (!video) return;
    video.playbackRate = rate;
    setPlaybackRate(rate);
    setShowSpeedMenu(false);
  }, []);

  const progress = duration > 0 ? (currentTime / duration) * 100 : 0;

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/90 p-4">
      {/* Close button */}
      {onClose && (
        <Button
          variant="ghost"
          size="icon"
          className="absolute end-4 top-4 z-10 text-white hover:bg-white/10"
          onClick={onClose}
          aria-label="إغلاق"
        >
          <X className="h-5 w-5" />
        </Button>
      )}

      {/* Title */}
      {title && (
        <div className="absolute start-4 top-4 z-10">
          <p className="text-sm font-medium text-white">{title}</p>
        </div>
      )}

      <div ref={containerRef} className="relative w-full max-w-5xl">
        <video
          ref={videoRef}
          src={src}
          poster={poster}
          autoPlay={autoPlay}
          className="w-full rounded-lg"
          onClick={togglePlay}
        />

        {/* Controls overlay */}
        <div className="absolute bottom-0 left-0 right-0 space-y-2 rounded-b-lg bg-gradient-to-t from-black/80 to-transparent p-4">
          {/* Seek bar */}
          <div className="flex items-center gap-2">
            <span className="text-xs text-white">
              {formatDuration(currentTime)}
            </span>
            <input
              type="range"
              min={0}
              max={duration || 0}
              value={currentTime}
              onChange={handleSeek}
              className="flex-1 accent-primary"
              aria-label="الانتقال"
            />
            <span className="text-xs text-white">
              {formatDuration(duration)}
            </span>
          </div>

          {/* Buttons */}
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-2">
              <Button
                variant="ghost"
                size="icon"
                className="h-8 w-8 text-white hover:bg-white/10"
                onClick={togglePlay}
                aria-label={isPlaying ? "إيقاف مؤقت" : "تشغيل"}
              >
                {isPlaying ? <Pause className="h-4 w-4" /> : <Play className="h-4 w-4" />}
              </Button>

              {/* Volume */}
              <div className="flex items-center gap-1">
                <Button
                  variant="ghost"
                  size="icon"
                  className="h-8 w-8 text-white hover:bg-white/10"
                  onClick={toggleMute}
                  aria-label={isMuted ? "تشغيل الصوت" : "كتم الصوت"}
                >
                  {isMuted ? <VolumeX className="h-4 w-4" /> : <Volume2 className="h-4 w-4" />}
                </Button>
                <input
                  type="range"
                  min={0}
                  max={1}
                  step={0.05}
                  value={isMuted ? 0 : volume}
                  onChange={handleVolume}
                  className="w-20 accent-primary"
                  aria-label="مستوى الصوت"
                />
              </div>

              {/* Playback speed */}
              <div className="relative">
                <Button
                  variant="ghost"
                  size="icon"
                  className="h-8 w-8 text-white hover:bg-white/10"
                  onClick={() => setShowSpeedMenu((s) => !s)}
                  aria-label="سرعة التشغيل"
                >
                  <Settings className="h-4 w-4" />
                </Button>
                {showSpeedMenu && (
                  <div className="absolute bottom-full end-0 mb-2 rounded-lg border bg-popover p-1 shadow-lg">
                    {PLAYBACK_SPEEDS.map((rate) => (
                      <button
                        key={rate}
                        onClick={() => changePlaybackRate(rate)}
                        className={`block w-full rounded px-3 py-1.5 text-xs transition-colors hover:bg-accent ${
                          playbackRate === rate ? "font-bold text-primary" : ""
                        }`}
                      >
                        {rate}x
                      </button>
                    ))}
                  </div>
                )}
              </div>
            </div>

            {/* Fullscreen */}
            <Button
              variant="ghost"
              size="icon"
              className="h-8 w-8 text-white hover:bg-white/10"
              onClick={toggleFullscreen}
              aria-label={isFullscreen ? "إنهاء ملء الشاشة" : "ملء الشاشة"}
            >
              {isFullscreen ? <Minimize className="h-4 w-4" /> : <Maximize className="h-4 w-4" />}
            </Button>
          </div>
        </div>
      </div>
    </div>
  );
}

"use client";

import { useState, useCallback } from "react";
import { X, Send, Loader2, MessageSquare } from "lucide-react";

import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { createCommentAction } from "@/actions/reviews/create-comment";
import type { CommentItem } from "@/types/review";

/* ============================================
   CommentForm — Create comment or reply
   ============================================ */

type CommentFormProps = {
  videoId: string;
  deliveryId: string;
  timestampSeconds: number;
  parentId?: string;
  authorName?: string;
  authorEmail?: string;
  onSubmitted?: (comment: CommentItem) => void;
  onCancel?: () => void;
};

export function CommentForm({
  videoId,
  deliveryId,
  timestampSeconds,
  parentId,
  authorName = "",
  authorEmail = "",
  onSubmitted,
  onCancel,
}: CommentFormProps) {
  const [name, setName] = useState(authorName);
  const [email, setEmail] = useState(authorEmail);
  const [message, setMessage] = useState("");
  const [submitting, setSubmitting] = useState(false);
  const [error, setError] = useState("");

  const isReply = !!parentId;

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!name.trim() || !email.trim() || !message.trim()) return;

    setSubmitting(true);
    setError("");

    try {
      const result = await createCommentAction({
        videoId,
        deliveryId,
        authorName: name,
        authorEmail: email,
        message,
        timestampSeconds,
        parentId,
      });

      if (result.success) {
        setMessage("");
        onSubmitted?.({
          id: result.commentId ?? "",
          commentCode: "",
          videoId,
          deliveryId,
          parentId: parentId ?? null,
          authorName: name.trim(),
          authorEmail: email.trim().toLowerCase(),
          authorType: "CLIENT",
          message: message.trim(),
          timestampSeconds,
          status: "OPEN",
          resolvedAt: null,
          createdAt: new Date(),
          updatedAt: new Date(),
          canEdit: true,
          replies: [],
        });
      } else {
        setError(result.error ?? "فشل في إرسال التعليق");
      }
    } catch {
      setError("فشل في إرسال التعليق");
    } finally {
      setSubmitting(false);
    }
  };

  return (
    <form onSubmit={handleSubmit} className="space-y-2">
      {!isReply && !name && (
        <div className="grid grid-cols-2 gap-2">
          <Input
            placeholder="الاسم"
            value={name}
            onChange={(e) => setName(e.target.value)}
            className="h-8 text-xs"
          />
          <Input
            type="email"
            placeholder="البريد الإلكتروني"
            value={email}
            onChange={(e) => setEmail(e.target.value)}
            className="h-8 text-xs"
          />
        </div>
      )}
      <div className="flex items-start gap-2">
        <textarea
          placeholder={isReply ? "اكتب رداً..." : "اكتب تعليقاً..."}
          value={message}
          onChange={(e) => setMessage(e.target.value)}
          rows={isReply ? 2 : 3}
          className="flex-1 rounded-md border border-input bg-transparent px-3 py-2 text-xs shadow-sm placeholder:text-muted-foreground focus-visible:outline-none focus-visible:ring-1 focus-visible:ring-ring"
        />
      </div>
      {error && <p className="text-xs text-destructive">{error}</p>}
      <div className="flex items-center justify-end gap-2">
        {onCancel && (
          <Button type="button" variant="ghost" size="sm" onClick={onCancel} disabled={submitting}>
            إلغاء
          </Button>
        )}
        <Button type="submit" size="sm" disabled={submitting || !message.trim()}>
          {submitting ? <Loader2 className="h-3.5 w-3.5 animate-spin" /> : <Send className="h-3.5 w-3.5" />}
          إرسال
        </Button>
      </div>
    </form>
  );
}

"use client";

import { useState } from "react";
import {
  Reply,
  CheckCircle2,
  RotateCcw,
  Archive,
  Clock,
  User,
} from "lucide-react";

import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { formatDuration } from "@/lib/video/metadata";
import { formatDate } from "@/lib/utils/format";
import { CommentForm } from "@/components/review/comment-form";
import { resolveCommentAction } from "@/actions/reviews/resolve-comment";
import { reopenCommentAction } from "@/actions/reviews/reopen-comment";
import { archiveCommentAction } from "@/actions/reviews/archive-comment";
import type { CommentItem } from "@/types/review";

/* ============================================
   CommentItem — Single comment with replies
   ============================================ */

type CommentItemProps = {
  comment: CommentItem;
  deliveryId: string;
  onSeek?: (seconds: number) => void;
  onReply?: () => void;
  isTeam?: boolean;
};

function StatusBadge({ status }: { status: string }) {
  if (status === "RESOLVED") return <Badge className="bg-green-600 hover:bg-green-600">محلول</Badge>;
  if (status === "ARCHIVED") return <Badge variant="secondary">مؤرشف</Badge>;
  return <Badge variant="outline">مفتوح</Badge>;
}

export function CommentItem({
  comment,
  deliveryId,
  onSeek,
  isTeam = false,
}: CommentItemProps) {
  const [showReplyForm, setShowReplyForm] = useState(false);
  const [actionLoading, setActionLoading] = useState(false);

  const handleAction = async (action: "resolve" | "reopen" | "archive") => {
    setActionLoading(true);
    try {
      if (action === "resolve") await resolveCommentAction(comment.id);
      if (action === "reopen") await reopenCommentAction(comment.id);
      if (action === "archive") await archiveCommentAction(comment.id);
    } finally {
      setActionLoading(false);
    }
  };

  return (
    <div className="space-y-2 rounded-lg border p-3">
      {/* Header */}
      <div className="flex items-center justify-between gap-2">
        <div className="flex items-center gap-2">
          <span className="flex h-6 w-6 items-center justify-center rounded-full bg-muted">
            <User className="h-3 w-3 text-muted-foreground" />
          </span>
          <span className="text-xs font-medium">{comment.authorName}</span>
          <StatusBadge status={comment.status} />
        </div>
        <span className="text-xs text-muted-foreground">
          {formatDate(comment.createdAt)}
        </span>
      </div>

      {/* Timestamp */}
      {onSeek && (
        <button
          onClick={() => onSeek(comment.timestampSeconds)}
          className="flex items-center gap-1 text-xs text-primary hover:underline"
        >
          <Clock className="h-3 w-3" />
          {formatDuration(comment.timestampSeconds)}
        </button>
      )}

      {/* Message */}
      <p className="text-sm leading-relaxed">{comment.message}</p>

      {/* Actions */}
      <div className="flex items-center gap-2">
        <Button
          variant="ghost"
          size="sm"
          className="h-7 text-xs"
          onClick={() => setShowReplyForm((s) => !s)}
        >
          <Reply className="h-3 w-3" />
          رد
        </Button>

        {isTeam && comment.status === "OPEN" && (
          <Button
            variant="ghost"
            size="sm"
            className="h-7 text-xs text-green-600 hover:text-green-600"
            onClick={() => handleAction("resolve")}
            disabled={actionLoading}
          >
            <CheckCircle2 className="h-3 w-3" />
            حل
          </Button>
        )}

        {isTeam && comment.status === "RESOLVED" && (
          <Button
            variant="ghost"
            size="sm"
            className="h-7 text-xs"
            onClick={() => handleAction("reopen")}
            disabled={actionLoading}
          >
            <RotateCcw className="h-3 w-3" />
            إعادة فتح
          </Button>
        )}

        {isTeam && (
          <Button
            variant="ghost"
            size="sm"
            className="h-7 text-xs text-muted-foreground"
            onClick={() => handleAction("archive")}
            disabled={actionLoading}
          >
            <Archive className="h-3 w-3" />
            أرشفة
          </Button>
        )}
      </div>

      {/* Replies */}
      {comment.replies.length > 0 && (
        <div className="space-y-2 border-s-2 border-muted ps-3">
          {comment.replies.map((reply) => (
            <div key={reply.id} className="rounded-md bg-muted/30 p-2">
              <div className="flex items-center justify-between">
                <span className="text-xs font-medium">{reply.authorName}</span>
                <span className="text-xs text-muted-foreground">
                  {formatDate(reply.createdAt)}
                </span>
              </div>
              <p className="mt-1 text-sm">{reply.message}</p>
            </div>
          ))}
        </div>
      )}

      {/* Reply Form */}
      {showReplyForm && (
        <div className="border-t pt-2">
          <CommentForm
            videoId={comment.videoId}
            deliveryId={deliveryId}
            timestampSeconds={comment.timestampSeconds}
            parentId={comment.id}
            onCancel={() => setShowReplyForm(false)}
          />
        </div>
      )}
    </div>
  );
}

"use client";

import { useState, useEffect, useRef } from "react";
import { Search, MessageSquare, ArrowUpDown, X } from "lucide-react";

import { Input } from "@/components/ui/input";
import { Button } from "@/components/ui/button";
import { EmptyState } from "@/components/shared/empty-state";
import { CommentItem } from "@/components/review/comment-item";
import { CommentForm } from "@/components/review/comment-form";
import { getCommentsAction } from "@/actions/reviews/get-comments";
import type { CommentItem as CommentItemType } from "@/types/review";
import type { CommentFilterValue, CommentSortValue } from "@/lib/validations/review";

/* ============================================
   CommentsPanel — Right side panel (desktop)
   / Bottom sheet (mobile)
   ============================================ */

type CommentsPanelProps = {
  videoId: string;
  deliveryId: string;
  onClose?: () => void;
  onSeek?: (seconds: number) => void;
  isTeam?: boolean;
};

const FILTER_OPTIONS: { value: CommentFilterValue; label: string }[] = [
  { value: "all", label: "الكل" },
  { value: "open", label: "مفتوح" },
  { value: "resolved", label: "محلول" },
  { value: "archived", label: "مؤرشف" },
];

const SORT_OPTIONS: { value: CommentSortValue; label: string }[] = [
  { value: "newest", label: "الأحدث" },
  { value: "oldest", label: "الأقدم" },
  { value: "timestamp", label: "الطابع الزمني" },
];

export function CommentsPanel({
  videoId,
  deliveryId,
  onClose,
  onSeek,
  isTeam = false,
}: CommentsPanelProps) {
  const [comments, setComments] = useState<CommentItemType[]>([]);
  const [loading, setLoading] = useState(true);
  const [search, setSearch] = useState("");
  const [filter, setFilter] = useState<CommentFilterValue>("all");
  const [sort, setSort] = useState<CommentSortValue>("timestamp");
  const [showForm, setShowForm] = useState(false);
  const hasFetched = useRef(false);

  useEffect(() => {
    if (!hasFetched.current) {
      hasFetched.current = true;
    }
    let active = true;
    (async () => {
      const result = await getCommentsAction({
        videoId,
        deliveryId,
        search: search || undefined,
        filter,
        sort,
      });
      if (!active) return;
      setComments(result.items);
      setLoading(false);
    })();
    return () => { active = false };
  }, [videoId, deliveryId, search, filter, sort]);

  return (
    <div className="flex h-full flex-col">
      {/* Header */}
      <div className="flex items-center justify-between border-b p-3">
        <h3 className="flex items-center gap-2 text-sm font-semibold">
          <MessageSquare className="h-4 w-4" />
          التعليقات ({comments.length})
        </h3>
        {onClose && (
          <Button variant="ghost" size="icon" className="h-7 w-7" onClick={onClose} aria-label="إغلاق">
            <X className="h-4 w-4" />
          </Button>
        )}
      </div>

      {/* Search + Filter */}
      <div className="space-y-2 border-b p-3">
        <div className="relative">
          <Search className="pointer-events-none absolute start-2.5 top-1/2 h-3.5 w-3.5 -translate-y-1/2 text-muted-foreground" />
          <Input
            type="search"
            placeholder="بحث في التعليقات..."
            className="h-8 ps-8 text-xs"
            value={search}
            onChange={(e) => setSearch(e.target.value)}
          />
        </div>
        <div className="flex items-center gap-1">
          {FILTER_OPTIONS.map((opt) => (
            <button
              key={opt.value}
              onClick={() => setFilter(opt.value)}
              className={`rounded-md px-2 py-1 text-xs transition-colors ${
                filter === opt.value ? "bg-primary text-primary-foreground" : "text-muted-foreground hover:bg-muted"
              }`}
            >
              {opt.label}
            </button>
          ))}
        </div>
      </div>

      {/* Comments List */}
      <div className="flex-1 overflow-y-auto p-3">
        {loading ? (
          <div className="flex items-center justify-center py-8">
            <div className="h-6 w-6 animate-spin rounded-full border-2 border-muted border-t-primary" />
          </div>
        ) : comments.length === 0 ? (
          <EmptyState
            icon={MessageSquare}
            title="لا توجد تعليقات"
            description="اضغط على الفيديو لإضافة تعليق"
            className="py-12"
          />
        ) : (
          <div className="space-y-2">
            {comments.map((comment) => (
              <CommentItem
                key={comment.id}
                comment={comment}
                deliveryId={deliveryId}
                onSeek={onSeek}
                isTeam={isTeam}
              />
            ))}
          </div>
        )}
      </div>
    </div>
  );
}

"use client";

import { useRef, useState, useEffect, useCallback } from "react";
import { MessageSquare, X, CheckCircle2, Loader2 } from "lucide-react";

import { Button } from "@/components/ui/button";
import { VideoPlayer } from "@/components/player/video-player";
import { CommentsPanel } from "@/components/review/comments-panel";
import { CommentForm } from "@/components/review/comment-form";
import { getCommentsAction } from "@/actions/reviews/get-comments";
import { approveVideoAction } from "@/actions/reviews/approve-video";
import { formatDuration } from "@/lib/video/metadata";
import type { TimelineMarker } from "@/types/review";

/* ============================================
   ReviewPlayer — VideoPlayer + Review System
   Wraps existing VideoPlayer without rewriting it.
   Adds timeline markers, comments panel, approval.
   ============================================ */

type ReviewPlayerProps = {
  src: string;
  title?: string;
  poster?: string;
  onClose?: () => void;
  autoPlay?: boolean;
  videoId: string;
  deliveryId: string;
  duration?: number;
};

export function ReviewPlayer({
  src,
  title,
  poster,
  onClose,
  autoPlay = false,
  videoId,
  deliveryId,
}: ReviewPlayerProps) {
  const videoRef = useRef<HTMLVideoElement>(null);
  const [showPanel, setShowPanel] = useState(false);
  const [markers, setMarkers] = useState<TimelineMarker[]>([]);
  const [currentTime, setCurrentTime] = useState(0);
  const [duration, setDuration] = useState(0);
  const [showCommentForm, setShowCommentForm] = useState(false);
  const [approving, setApproving] = useState(false);
  const [approved, setApproved] = useState(false);

  // Fetch timeline markers
  useEffect(() => {
    let active = true;
    (async () => {
      const result = await getCommentsAction({ videoId, deliveryId });
      if (!active) return;
      setMarkers(
        result.items.map((c) => ({
          id: c.id,
          commentCode: c.commentCode,
          timestampSeconds: c.timestampSeconds,
          authorName: c.authorName,
          message: c.message,
          status: c.status,
        }))
      );
    })();
    return () => { active = false };
  }, [videoId, deliveryId]);

  // Track current time from the video element
  useEffect(() => {
    const video = videoRef.current;
    if (!video) return;

    const onTimeUpdate = () => setCurrentTime(video.currentTime);
    const onLoadedMetadata = () => setDuration(video.duration);

    video.addEventListener("timeupdate", onTimeUpdate);
    video.addEventListener("loadedmetadata", onLoadedMetadata);

    return () => {
      video.removeEventListener("timeupdate", onTimeUpdate);
      video.removeEventListener("loadedmetadata", onLoadedMetadata);
    };
  }, []);

  const handleSeek = useCallback((seconds: number) => {
    const video = videoRef.current;
    if (!video) return;
    video.currentTime = seconds;
    video.pause();
  }, []);

  const handleVideoClick = useCallback(() => {
    const video = videoRef.current;
    if (!video) return;
    // Pause and open comment form at current position
    video.pause();
    setCurrentTime(video.currentTime);
    setShowCommentForm(true);
  }, []);

  const handleApprove = async () => {
    setApproving(true);
    try {
      const result = await approveVideoAction({ videoId, deliveryId, deliverySlug: "" });
      if (result.success) {
        setApproved(true);
      }
    } finally {
      setApproving(false);
    }
  };

  const progress = duration > 0 ? (currentTime / duration) * 100 : 0;

  return (
    <div className="fixed inset-0 z-50 flex bg-black/95">
      {/* Close button */}
      {onClose && (
        <Button
          variant="ghost"
          size="icon"
          className="absolute end-4 top-4 z-10 text-white hover:bg-white/10"
          onClick={onClose}
          aria-label="إغلاق"
        >
          <X className="h-5 w-5" />
        </Button>
      )}

      {/* Title */}
      {title && (
        <div className="absolute start-4 top-4 z-10">
          <p className="text-sm font-medium text-white">{title}</p>
        </div>
      )}

      {/* Video area */}
      <div className="flex flex-1 items-center justify-center p-4">
        <div className="relative w-full max-w-4xl">
          <video
            ref={videoRef}
            src={src}
            poster={poster}
            autoPlay={autoPlay}
            className="w-full rounded-lg"
            controls
          />

          {/* Timeline markers overlay */}
          {duration > 0 && (
            <div className="absolute bottom-[60px] left-0 right-0 h-2 px-4">
              <div className="relative h-full">
                {markers.map((marker) => {
                  const left = (marker.timestampSeconds / duration) * 100;
                  return (
                    <div
                      key={marker.id}
                      className="absolute -top-1 h-4 w-1 cursor-pointer rounded-full bg-amber-400 transition-transform hover:scale-150"
                      style={{ left: `${left}%` }}
                      title={`${formatDuration(marker.timestampSeconds)} — ${marker.authorName}: ${marker.message.slice(0, 50)}`}
                      onClick={() => handleSeek(marker.timestampSeconds)}
                    />
                  );
                })}
              </div>
            </div>
          )}

          {/* Comment on click overlay */}
          <button
            className="absolute inset-0 opacity-0"
            onDoubleClick={handleVideoClick}
            aria-label="اضغط مرتين لإضافة تعليق"
          />
        </div>
      </div>

      {/* Comment Form Dialog */}
      {showCommentForm && (
        <div className="absolute bottom-20 left-1/2 z-20 w-96 max-w-[90%] -translate-x-1/2 rounded-lg border bg-popover p-4 shadow-xl">
          <div className="mb-3 flex items-center justify-between">
            <p className="text-sm font-medium">
              تعليق عند {formatDuration(currentTime)}
            </p>
            <Button variant="ghost" size="icon" className="h-7 w-7" onClick={() => setShowCommentForm(false)}>
              <X className="h-4 w-4" />
            </Button>
          </div>
          <CommentForm
            videoId={videoId}
            deliveryId={deliveryId}
            timestampSeconds={Math.floor(currentTime)}
            onSubmitted={() => {
              setShowCommentForm(false);
              setShowPanel(true);
              // Refresh markers
              getCommentsAction({ videoId, deliveryId }).then((result) => {
                setMarkers(
                  result.items.map((c) => ({
                    id: c.id,
                    commentCode: c.commentCode,
                    timestampSeconds: c.timestampSeconds,
                    authorName: c.authorName,
                    message: c.message,
                    status: c.status,
                  }))
                );
              });
            }}
          />
        </div>
      )}

      {/* Comments Panel Toggle */}
      <Button
        variant="secondary"
        size="sm"
        className="absolute bottom-4 end-4 z-10"
        onClick={() => setShowPanel((s) => !s)}
      >
        <MessageSquare className="h-4 w-4" />
        التعليقات
        {markers.length > 0 && (
          <span className="ms-1 rounded-full bg-primary px-1.5 py-0.5 text-xs text-primary-foreground">
            {markers.length}
          </span>
        )}
      </Button>

      {/* Approve Button */}
      <Button
        variant={approved ? "default" : "outline"}
        size="sm"
        className="absolute bottom-4 start-4 z-10"
        onClick={handleApprove}
        disabled={approving || approved}
      >
        {approving ? (
          <Loader2 className="h-4 w-4 animate-spin" />
        ) : approved ? (
          <CheckCircle2 className="h-4 w-4" />
        ) : null}
        {approved ? "معتمد" : "اعتماد الفيديو"}
      </Button>

      {/* Comments Panel */}
      {showPanel && (
        <div className="absolute end-0 top-0 z-20 h-full w-96 max-w-[90%] border-s bg-card">
          <CommentsPanel
            videoId={videoId}
            deliveryId={deliveryId}
            onClose={() => setShowPanel(false)}
            onSeek={handleSeek}
          />
        </div>
      )}
    </div>
  );
}

import { BRANDING } from "@/config/branding";

/* ============================================
   Public Gallery Page (token-based)
   Stabilization stub — to be implemented in a
