  DELIVERED: "تم التسليم",
  PAID: "مدفوع",
  COMPLETED: "مكتمل",
  ARCHIVED: "مؤرشف",
};

/** Ordered workflow steps for visual progress. */
export const WORKFLOW_ORDER: ProjectWorkflowStatus[] = [
  "NEW",
  "PLANNING",
  "SHOOTING",
  "EDITING",
  "REVIEW",
  "APPROVED",
  "DELIVERED",
