import { deliveryService } from "@/services/delivery.service";
import { activityService } from "@/services/activity.service";
import { deliveryRepository } from "@/repositories/delivery.repository";

/* ============================================
   Track Download Server Action (Public)
   Increments download count, returns signed URL.
   No authentication required.
   ============================================ */

export async function trackDownloadAction(
  deliveryId: string,
  videoId: string,
  storageKey: string
): Promise<{
  success: boolean;
  url?: string;
  error?: string;
}> {
  const delivery = await deliveryRepository.findById(deliveryId);

  if (!delivery || !delivery.downloadEnabled) {
    return { success: false, error: "التحميل غير متاح" };
  }

  const accessStatus = deliveryService.checkAccess(delivery);

  if (accessStatus !== "active") {
    return { success: false, error: "التسليم غير متاح" };
  }

  try {
    const url = await deliveryService.trackDownload(deliveryId, storageKey);

    // Log download activity
    await activityService.log({
      userId: delivery.project.clientId,
      type: "DOWNLOAD_STARTED",
      entity: "delivery",
      entityId: deliveryId,
      metadata: { deliveryCode: delivery.deliveryCode, videoId },
    }).catch(() => {});

    return { success: true, url };
  } catch {
    return { success: false, error: "فشل في توليد رابط التحميل" };
  }
}

"use server";

import { reviewService } from "@/services/review.service";
import { createCommentSchema } from "@/lib/validations/review";

/* ============================================
   Create Comment Server Action (Public)
   No authentication required — public delivery portal.
   Rate-limited by delivery slug + email.
   ============================================ */

export async function createCommentAction(params: {
  videoId: string;
  deliveryId: string;
  authorName: string;
  authorEmail: string;
  message: string;
  timestampSeconds: number;
  parentId?: string;
}): Promise<{
  success: boolean;
  error?: string;
  commentId?: string;
}> {
  const parsed = createCommentSchema.safeParse({
    videoId: params.videoId,
    deliveryId: params.deliveryId,
    authorName: params.authorName,
    authorEmail: params.authorEmail,
    authorType: "CLIENT",
    message: params.message,
    timestampSeconds: params.timestampSeconds,
    parentId: params.parentId || "",
  });

  if (!parsed.success) {
    return {
      success: false,
      error: parsed.error.issues[0]?.message ?? "بيانات غير صالحة",
    };
  }

  try {
    const comment = await reviewService.create({
      videoId: parsed.data.videoId,
      deliveryId: parsed.data.deliveryId,
      authorName: parsed.data.authorName,
      authorEmail: parsed.data.authorEmail,
      authorType: "CLIENT",
      message: parsed.data.message,
      timestampSeconds: parsed.data.timestampSeconds,
      parentId: parsed.data.parentId || undefined,
    });

    return { success: true, commentId: comment.id };
  } catch {
    return { success: false, error: "فشل في إنشاء التعليق" };
  }
}

