import { requireRole } from "@/lib/auth/session";
import type { UserRole } from "@/types/auth";

/* ============================================
   Role Permissions & Route Guards
   ============================================ */

/**
 * Role hierarchy for reference:
 *
 * OWNER       — Full access (everything)
 * ADMIN       — Everything except owner settings
 * EDITOR      — Projects + Uploads only
 * MEDIA_BUYER — Read-only dashboard + Clients
 * PHOTOGRAPHER— Uploads only
 */

export type { UserRole };

/* ── Route Guard Helpers ─────────────────── */

/** Require the OWNER role. */
export function requireOwner() {
  return requireRole("OWNER");
}

/** Require OWNER or ADMIN. */
export function requireAdmin() {
  return requireRole("OWNER", "ADMIN");
}

/** Require OWNER, ADMIN, or EDITOR. */
export function requireEditor() {
  return requireRole("OWNER", "ADMIN", "EDITOR");
}

/** Require OWNER, ADMIN, or MEDIA_BUYER. */
export function requireMediaBuyer() {
  return requireRole("OWNER", "ADMIN", "MEDIA_BUYER");
}

/** Require OWNER, ADMIN, EDITOR, or PHOTOGRAPHER. */
export function requirePhotographer() {
  return requireRole("OWNER", "ADMIN", "EDITOR", "PHOTOGRAPHER");
}

/* ── Role Hierarchy (for reference) ──────── */

export const ROLE_HIERARCHY: readonly UserRole[] = [
  "OWNER",
  "ADMIN",
  "EDITOR",
  "MEDIA_BUYER",
  "PHOTOGRAPHER",
  "CLIENT",
] as const;

/**
 * Check whether a role has sufficient privilege.
 * Lower index = higher privilege.
 */
export function hasMinimumRole(
  userRole: UserRole,
  minRole: UserRole
): boolean {
  const userIdx = ROLE_HIERARCHY.indexOf(userRole);
  const minIdx = ROLE_HIERARCHY.indexOf(minRole);
  return userIdx !== -1 && minIdx !== -1 && userIdx <= minIdx;
}

import { getCurrentUser, requireUser, requireRole } from "@/lib/auth/session";
import type { UserRole } from "@prisma/client";

/* ============================================
   RBAC Utilities
   Role-Based Access Control helpers.
   Use these to protect Server Actions.
   ============================================ */

/** All roles in the system. */
export const ALL_ROLES: UserRole[] = [
  "OWNER",
  "ADMIN",
  "EDITOR",
  "MEDIA_BUYER",
  "PHOTOGRAPHER",
  "CLIENT",
];

/** Management roles — can access dashboard. */
export const MANAGEMENT_ROLES: UserRole[] = [
  "OWNER",
  "ADMIN",
  "EDITOR",
  "MEDIA_BUYER",
  "PHOTOGRAPHER",
];

/** Admin roles — full access. */
export const ADMIN_ROLES: UserRole[] = ["OWNER", "ADMIN"];

/** Check if a user has a specific role. */
export function hasRole(userRole: UserRole | undefined, ...roles: UserRole[]): boolean {
  if (!userRole) return false;
  return roles.includes(userRole);
}

/** Check if user is admin (OWNER or ADMIN). */
export function isAdmin(userRole: UserRole | undefined): boolean {
  return hasRole(userRole, "OWNER", "ADMIN");
}

/** Check if user is owner. */
export function isOwner(userRole: UserRole | undefined): boolean {
  return userRole === "OWNER";
}

/** Check if user can manage (admin or management). */
export function canManage(userRole: UserRole | undefined): boolean {
  return hasRole(userRole, ...MANAGEMENT_ROLES);
}

// ── Server-side guards ─────────────────────

/** Require any authenticated user. */
export async function requireAuth() {
  return requireUser();
}

/** Require admin (OWNER or ADMIN). */
export async function requireAdmin() {
  return requireRole("OWNER", "ADMIN");
}

/** Require management role (dashboard access). */
export async function requireManagement() {
  return requireRole(...MANAGEMENT_ROLES);
}

/** Get current user or null (for optional auth checks). */
export async function getOptionalUser() {
  return getCurrentUser();
}

