export async function transitionWorkflowAction(params: {
  projectId: string;
  toStatus: ProjectWorkflowStatus;
}): Promise<{
  success: boolean;
  error?: string;
  fromStatus?: ProjectWorkflowStatus;
  toStatus?: ProjectWorkflowStatus;
}> {
  const user = await getCurrentUser();
  if (!user) {
    return { success: false, error: "يجب تسجيل الدخول" };
